insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 10, 'Simplify: 2/5 of 150 + 18.', 'Simplify करें: 150 का 2/5 + 18.', '2/5 of 150 = 150 ÷ 5 × 2 = 60. Then 60+18=78. Therefore, answer = 78.', '''Of'' means multiplication. Compute the fraction of the given number first, then apply the outside addition. Final answer is 78.', '150 का 2/5 = 150 ÷ 5 × 2 = 60। फिर 60+18=78। अतः answer = 78।', '''of'' का मतलब multiplication है। पहले fraction of number निकालें, फिर बाहर वाला addition करें। Final answer 78 है।', 'MEDIUM', array['simplification','fractions']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
