insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 23, 'Simplify using identity: 23² - 7².', 'Identity से simplify करें: 23² - 7².', 'a²-b²=(a-b)(a+b)=(23-7)(23+7)=16×30=480. Therefore, answer = 480.', 'The difference of squares identity avoids large square calculations and is a standard simplification shortcut. Final answer is 480.', 'a²-b²=(a-b)(a+b)=(23-7)(23+7)=16×30=480। अतः answer = 480।', 'Difference of squares identity बड़े square calculations बचाती है और simplification का standard shortcut है। Final answer 480 है।', 'HARD', array['simplification','identities']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
